import{_ as o}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as r,c as t,f as i}from"./app.f62a8256.js";const e={},a=i('<h1 id="_2\u9636\u6BB5\u548C3\u9636\u6BB5\u63D0\u4EA4" tabindex="-1"><a class="header-anchor" href="#_2\u9636\u6BB5\u548C3\u9636\u6BB5\u63D0\u4EA4" aria-hidden="true">#</a> 2\u9636\u6BB5\u548C3\u9636\u6BB5\u63D0\u4EA4</h1><blockquote><p>\u6765\u81EA\u4E8EAlluxio\u526F\u603B\u88C1\u8303\u658C\u7684\u6587\u7AE0</p><p>\u4F5C\u8005\uFF1A\u8303\u658C</p></blockquote><p>2PC (\u4E24\u9636\u6BB5\u63D0\u4EA4)\u534F\u8BAE\u548C3PC (\u4E09\u9636\u6BB5\u63D0\u4EA4)\u534F\u8BAE\u672C\u8EAB\u5176\u5B9E\u5F88\u7B80\u5355. \u6211\u5C3D\u91CF\u901A\u8FC7\u5C11\u5199\u5B57, \u591A\u4E0A\u56FE\u7684\u65B9\u6CD5, \u7528\u4E00\u4E2Acoordinator\u548C\u4E09\u4E2Avoter\u8FBE\u6210\u5171\u8BC6\u7684\u4F8B\u5B50\u6765\u8BF4\u660E\u8FD9\u4E24\u4E2A\u534F\u8BAE\u7684\u60F3\u6CD5.</p><h2 id="_2pc-\u4E24\u9636\u6BB5\u63D0\u4EA4-\u534F\u8BAE" tabindex="-1"><a class="header-anchor" href="#_2pc-\u4E24\u9636\u6BB5\u63D0\u4EA4-\u534F\u8BAE" aria-hidden="true">#</a> 2PC (\u4E24\u9636\u6BB5\u63D0\u4EA4)\u534F\u8BAE</h2><p><strong>2PC\u7684\u539F\u7406</strong></p><p>\u987E\u540D\u601D\u4E49, 2PC\u534F\u8BAE\u6709\u4E24\u4E2A\u9636\u6BB5:Propose\u548CCommit. <strong>\u5728\u65E0failure\u60C5\u51B5\u4E0B</strong>\u76842PC\u534F\u8BAE\u6D41\u7A0B\u7684\u753B\u98CE\u662F\u8FD9\u6837\u7684:</p><ul><li><p>Propose\u9636\u6BB5:</p></li><li><ul><li>coordinator: &quot;\u6628\u591C\u9A8C\u4EBA\u6709\u60CA\u559C, \u4ECA\u5929\u90FD\u6295\u7968\u51FA\u516D\u5A03&quot;</li><li>voter1/voter2/voter3: &quot;\u597D\u7684\u5973\u738B\u5927\u4EBA!&quot;</li></ul></li><li><p>Commit\u9636\u6BB5</p></li><li><ul><li>coordinator: &quot;\u6295\u516D\u5A03&quot;</li><li>voter1/voter2/voter3: &quot;\u6295\u4E86\u5973\u738B\u5927\u4EBA!&quot; (\u753B\u5916\u97F3: \u516D\u5A03\u6251\u8857)</li></ul></li></ul><p><img src="https://pic3.zhimg.com/v2-e2f7149a81d9ad3aa46589e25503d688_720w.jpg?source=d16d100b" alt="img" loading="lazy"><img src="https://pic3.zhimg.com/80/v2-e2f7149a81d9ad3aa46589e25503d688_1440w.jpg?source=d16d100b" alt="img" loading="lazy">\u56FE1: 2PC, coordinator\u63D0\u8BAE\u901A\u8FC7, voter{1,2,3}\u8FBE\u6210\u65B0\u7684\u5171\u8BC6</p><p>\u5982\u679C\u6709\u81F3\u5C11\u4E00\u4E2Avoter (\u6BD4\u5982voter3)\u5728Propose\u9636\u6BB5\u6295\u4E86\u53CD\u5BF9\u7968, \u90A3\u4E48propose\u901A\u8FC7\u5931\u8D25. coordinator\u5C31\u4F1A\u5728Commit(or abort)\u9636\u6BB5\u8DDF\u6240\u6709voter\u8BF4, \u653E\u5F03\u8FD9\u4E2Apropose.</p><p><img src="https://pic1.zhimg.com/v2-d40abfa365ed84e84e264ba13900f64b_720w.jpg?source=d16d100b" alt="img" loading="lazy"><img src="https://pic1.zhimg.com/80/v2-d40abfa365ed84e84e264ba13900f64b_1440w.jpg?source=d16d100b" alt="img" loading="lazy">\u56FE2: 2PC, coordinator\u63D0\u8BAE\u6CA1\u6709\u901A\u8FC7, voter{1,2,3}\u4FDD\u6301\u65E7\u6709\u7684\u5171\u8BC6</p><p><strong>2PC\u7684\u7F3A\u9677</strong></p><p>2PC\u7684\u7F3A\u70B9\u5728\u4E8E\u4E0D\u80FD\u5904\u7406fail-stop\u5F62\u5F0F\u7684\u8282\u70B9failure. \u6BD4\u5982\u4E0B\u56FE\u8FD9\u79CD\u60C5\u51B5. \u5047\u8BBEcoordinator\u548Cvoter3\u90FD\u5728Commit\u8FD9\u4E2A\u9636\u6BB5crash\u4E86, \u800Cvoter1\u548Cvoter2\u6CA1\u6709\u6536\u5230commit\u6D88\u606F. \u8FD9\u65F6\u5019voter1\u548Cvoter2\u5C31\u9677\u5165\u4E86\u4E00\u4E2A\u56F0\u5883. \u56E0\u4E3A\u4ED6\u4EEC\u5E76\u4E0D\u80FD\u5224\u65AD\u73B0\u5728\u662F\u4E24\u4E2A\u573A\u666F\u4E2D\u7684\u54EA\u4E00\u79CD: (1)\u4E0A\u8F6E\u5168\u7968\u901A\u8FC7\u7136\u540Evoter3\u7B2C\u4E00\u4E2A\u6536\u5230\u4E86commit\u7684\u6D88\u606F\u5E76\u5728commit\u64CD\u4F5C\u4E4B\u540Ecrash\u4E86, (2)\u4E0A\u8F6Evoter3\u53CD\u5BF9\u6240\u4EE5\u5E72\u8106\u6CA1\u6709\u901A\u8FC7.</p><p><img src="https://pic2.zhimg.com/v2-a9e4ef8b9082ffdf76bc426e61ba3ed2_720w.jpg?source=d16d100b" alt="img" loading="lazy"><img src="https://pic2.zhimg.com/80/v2-a9e4ef8b9082ffdf76bc426e61ba3ed2_1440w.jpg?source=d16d100b" alt="img" loading="lazy">\u56FE3: 2PC, coordinator\u548Cvoter3 crash, voter{1,2}\u65E0\u6CD5\u5224\u65AD\u5F53\u524D\u72B6\u6001\u800C\u5361\u6B7B</p><p>2PC\u5728\u8FD9\u79CDfail-stop\u60C5\u51B5\u4E0B\u4F1A\u5931\u8D25\u662F\u56E0\u4E3Avoter\u5728\u5F97\u77E5Propose Phase\u7ED3\u679C\u540E\u5C31\u76F4\u63A5commit\u4E86, \u800C\u5E76\u6CA1\u6709\u5728commit\u4E4B\u524D\u544A\u77E5\u5176\u4ED6voter\u81EA\u5DF1\u5DF2\u6536\u5230Propose Phase\u7684\u7ED3\u679C. \u4ECE\u800C\u5BFC\u81F4\u5728coordinator\u548C\u4E00\u4E2Avoter\u53CC\u53CC\u6389\u7EBF\u7684\u60C5\u51B5\u4E0B, \u5176\u4F59voter\u4E0D\u4F46\u65E0\u6CD5\u590D\u539FPropose Phase\u7684\u7ED3\u679C, \u4E5F\u65E0\u6CD5\u77E5\u9053\u6389\u7EBF\u7684voter\u662F\u5426\u6253\u7B97\u751A\u81F3\u5DF2\u7ECFcommit. \u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E00\u95EE\u9898, 3PC\u4E86\u89E3\u4E00\u4E0B.</p><hr><h2 id="_3pc-\u4E09\u9636\u6BB5\u63D0\u4EA4-\u534F\u8BAE" tabindex="-1"><a class="header-anchor" href="#_3pc-\u4E09\u9636\u6BB5\u63D0\u4EA4-\u534F\u8BAE" aria-hidden="true">#</a> 3PC (\u4E09\u9636\u6BB5\u63D0\u4EA4)\u534F\u8BAE</h2><p><strong>3PC\u7684\u539F\u7406</strong></p><p>\u7B80\u5355\u7684\u8BF4\u6765, 3PC\u5C31\u662F\u628A2PC\u7684Commit\u9636\u6BB5\u62C6\u6210\u4E86PreCommit\u548CCommit\u4E24\u4E2A\u9636\u6BB5. \u901A\u8FC7\u8FDB\u5165\u589E\u52A0\u7684\u8FD9\u4E00\u4E2APreCommit\u9636\u6BB5, voter\u53EF\u4EE5\u5F97\u5230Propose\u9636\u6BB5\u7684\u6295\u7968\u7ED3\u679C, \u4F46\u4E0D\u4F1Acommit; \u800C\u901A\u8FC7\u8FDB\u5165Commit\u9636\u6BB5, voter\u53EF\u4EE5\u76D8\u51FA\u5176\u4ED6\u6BCF\u4E2Avoter\u4E5F\u90FD\u6253\u7B97commit\u4E86, \u4ECE\u800C\u53EF\u4EE5\u653E\u5FC3\u7684commit.</p><p><strong>\u6362\u8A00\u4E4B, 3PC\u57282PC\u7684Commit\u9636\u6BB5\u91CC\u589E\u52A0\u4E86\u4E00\u4E2Abarrier</strong>(\u5373\u76F8\u5F53\u4E8E\u544A\u8BC9\u5176\u4ED6\u6240\u6709voter, \u6211\u6536\u5230\u4E86Propose\u7684\u7ED3\u679C\u5566). \u5728\u8FD9\u4E2Abarrier\u4E4B\u524Dcoordinator\u6389\u7EBF\u7684\u8BDD, \u5176\u4ED6voter\u53EF\u4EE5\u5F97\u51FA\u7ED3\u8BBA\u4E0D\u662F\u6BCF\u4E2Avoter\u90FD\u6536\u5230Propose Phase\u7684\u7ED3\u679C, \u4ECE\u800C\u653E\u5F03\u6216\u9009\u51FA\u65B0\u7684coordinator; \u5728\u8FD9\u4E2Abarrier\u4E4B\u540Ecoordinator\u6389\u7EBF\u7684\u8BDD, \u6BCF\u4E2Avoter\u4F1A\u653E\u5FC3\u7684commit, \u56E0\u4E3A\u4ED6\u4EEC\u77E5\u9053\u5176\u4ED6voter\u4E5F\u90FD\u505A\u540C\u6837\u7684\u8BA1\u5212.</p><p><img src="https://pic3.zhimg.com/v2-28c17c86e689007015a4853f0d0c4a89_720w.jpg?source=d16d100b" alt="img" loading="lazy"><img src="https://pic3.zhimg.com/80/v2-28c17c86e689007015a4853f0d0c4a89_1440w.jpg?source=d16d100b" alt="img" loading="lazy">\u56FE4: 3PC, coordinator\u63D0\u8BAE\u901A\u8FC7, voter{1,2,3}\u8FBE\u6210\u65B0\u7684\u5171\u8BC6</p><p><strong>3PC\u7684\u7F3A\u9677</strong></p><p>3PC\u53EF\u4EE5\u6709\u6548\u7684\u5904\u7406fail-stop\u7684\u6A21\u5F0F, \u4F46\u4E0D\u80FD\u5904\u7406\u7F51\u7EDC\u5212\u5206(network partition)\u7684\u60C5\u51B5---\u8282\u70B9\u4E92\u76F8\u4E0D\u80FD\u901A\u4FE1. \u5047\u8BBE\u5728PreCommit\u9636\u6BB5\u6240\u6709\u8282\u70B9\u88AB\u4E00\u5206\u4E3A\u4E8C, \u6536\u5230preCommit\u6D88\u606F\u7684voter\u5728\u4E00\u8FB9, \u800C\u6CA1\u6709\u6536\u5230\u8FD9\u4E2A\u6D88\u606F\u7684\u5728\u53E6\u5916\u4E00\u8FB9. \u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B, \u4E24\u8FB9\u5C31\u53EF\u80FD\u4F1A\u9009\u51FA\u65B0\u7684coordinator\u800C\u505A\u51FA\u4E0D\u540C\u7684\u51B3\u5B9A.</p><p><img src="https://pica.zhimg.com/v2-7a18adc27a2bd7b5f5926dd999bc7bb3_720w.jpg?source=d16d100b" alt="img" loading="lazy"><img src="https://pica.zhimg.com/80/v2-7a18adc27a2bd7b5f5926dd999bc7bb3_1440w.jpg?source=d16d100b" alt="img" loading="lazy">\u56FE5: 3PC, network partition, voter{1,2,3}\u5931\u53BB\u5171\u8BC6</p><p>\u9664\u4E86\u7F51\u7EDC\u5212\u5206\u4EE5\u5916, 3PC\u4E5F\u4E0D\u80FD\u5904\u7406fail-recover\u7684\u9519\u8BEF\u60C5\u51B5. \u7B80\u5355\u8BF4\u6765\u5F53coordinator\u6536\u5230preCommit\u7684\u786E\u8BA4\u524Dcrash, \u4E8E\u662F\u5176\u4ED6\u67D0\u4E00\u4E2Avoter\u63A5\u66FF\u4E86\u539Fcoordinator\u7684\u4EFB\u52A1\u800C\u5F00\u59CB\u7EC4\u7EC7\u6240\u6709voter commit. \u800C\u4E0E\u6B64\u540C\u65F6\u539Fcoordinator\u91CD\u542F\u540E\u53C8\u56DE\u5230\u4E86\u7F51\u7EDC\u4E2D, \u5F00\u59CB\u7EE7\u7EED\u4E4B\u524D\u7684\u56DE\u5408---\u53D1\u9001abort\u7ED9\u5404\u4F4Dvoter\u56E0\u4E3A\u5B83\u5E76\u6CA1\u6709\u6536\u5230preCommit. \u6B64\u65F6\u6709\u53EF\u80FD\u4F1A\u51FA\u73B0\u539Fcoordinator\u548C\u7EE7\u4EFB\u7684coordinator\u7ED9\u4E0D\u540C\u8282\u70B9\u53D1\u9001\u76F8\u77DB\u76FE\u7684commit\u548Cabort\u6307\u4EE4, \u4ECE\u800C\u51FA\u73B0\u4E2A\u8282\u70B9\u7684\u72B6\u6001\u5206\u6B67.</p><p>\u8FD9\u79CD\u60C5\u51B5\u7B49\u4EF7\u4E8E\u4E00\u4E2A\u66F4\u771F\u5B9E\u6216\u8005\u66F4\u8D1F\u8D23\u7684\u7F51\u7EDC\u73AF\u5883\u5047\u8BBE: \u5F02\u6B65\u7F51\u7EDC. \u5728\u8FD9\u79CD\u5047\u8BBE\u4E0B, \u7F51\u7EDC\u4F20\u8F93\u65F6\u95F4\u53EF\u80FD\u4EFB\u610F\u957F. \u4E3A\u4E86\u89E3\u51B3\u8FD9\u79CD\u60C5\u51B5, \u90A3\u5C31\u5F97\u8BF7\u51FA\u4E0B\u4E00\u7BC7\u7684\u4E3B\u89D2: Paxos</p><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><ol><li>2PC\u4F7F\u7528\u4E24\u4E2Aroundtrip\u6765\u8FBE\u6210\u65B0\u7684\u5171\u8BC6\u6216\u7EF4\u6301\u65E7\u6709\u7684\u5171\u8BC6. \u5176\u5C40\u9650\u6027\u5728\u4E8E\u4E0D\u80FD\u4FDD\u8BC1\u6709\u8282\u70B9\u6C38\u4E45\u6027\u5D29\u6E83(fail-stop)\u7684\u60C5\u51B5\u4E0B\u7B97\u6CD5\u80FD\u5411\u524D\u63A8\u8FDB;</li><li>3PC\u6269\u5C55\u4E862PC, \u4F7F\u7528\u4E09\u4E2Aroundtrip\u8FBE\u6210\u5171\u8BC6. \u5176\u5C40\u9650\u6027\u5728\u4E8E\u4E0D\u80FD\u4FDD\u8BC1\u5728\u8282\u70B9\u6682\u65F6\u6027\u5D29\u6E83(fail-recover), \u6216\u662F\u6709\u7F51\u7EDC\u5212\u5206\u7684\u60C5\u51B5\u4E0B, \u5171\u8BC6\u4F9D\u65E7\u6210\u7ACB.</li></ol>',27),c=[a];function p(d,m){return r(),t("div",null,c)}const n=o(e,[["render",p],["__file","2\u9636\u6BB5\u548C3\u9636\u6BB5\u63D0\u4EA4.html.vue"]]);export{n as default};
